## 1. **Complete VSIX Plugin System (CLI + GUI)**

### **vsix_loader.h** (Final)
```cpp
#pragma once
#include <string>
#include <vector>
#include <memory>
#include <filesystem>
#include <nlohmann/json.hpp>
#include <mutex>
#include <unordered_map>
#include <functional>

struct VSIXPlugin {
    std::string id;
    std::string name;
    std::string version;
    std::string description;
    std::string author;
    std::filesystem::path install_path;
    bool enabled;
    std::vector<std::string> commands;
    std::vector<std::string> dependencies;
    nlohmann::json manifest;
    std::function<void()> onLoad;
    std::function<void()> onUnload;
    std::function<void(const std::string&)> onCommand;
    std::function<void(const nlohmann::json&)> onConfigure;
};

class VSIXLoader {
private:
    std::filesystem::path plugins_dir_;
    std::unordered_map<std::string, std::unique_ptr<VSIXPlugin>> plugins_;
    std::mutex mutex_;
    std::unordered_map<std::string, std::function<void()>> command_handlers_;
    
public:
    VSIXLoader();
    ~VSIXLoader();
    
    // Core operations
    bool Initialize(const std::string& plugins_dir);
    bool LoadPlugin(const std::string& vsix_path);
    bool UnloadPlugin(const std::string& plugin_id);
    bool EnablePlugin(const std::string& plugin_id);
    bool DisablePlugin(const std::string& plugin_id);
    bool ReloadPlugin(const std::string& plugin_id);
    bool ConfigurePlugin(const std::string& plugin_id, const nlohmann::json& config);
    
    // Query operations
    std::vector<VSIXPlugin*> GetLoadedPlugins();
    VSIXPlugin* GetPlugin(const std::string& plugin_id);
    bool IsPluginLoaded(const std::string& plugin_id);
    bool IsPluginEnabled(const std::string& plugin_id);
    nlohmann::json GetPluginConfig(const std::string& plugin_id);
    std::string GetPluginHelp(const std::string& plugin_id);
    std::string GetAllPluginsHelp();
    std::string GetCLIHelp();
    std::string GetGUIHelp();
    
    // Execution
    bool ExecutePluginCommand(const std::string& plugin_id, const std::string& command, const std::vector<std::string>& args);
    std::string GetPluginUsage(const std::string& plugin_id);
    
    // Memory modules (special plugins)
    bool LoadMemoryModule(const std::string& module_path, size_t context_size);
    bool UnloadMemoryModule(size_t context_size);
    std::vector<size_t> GetAvailableMemoryModules();
    
    // Command registration
    void RegisterCommand(const std::string& command, std::function<void()> handler);
    bool ExecuteCommand(const std::string& command);
    
    // Help system
    std::string GetCommandHelp(const std::string& command);
    
    // Singleton access
    static VSIXLoader& GetInstance();
    
    // Engine management
    bool LoadEngine(const std::string& engine_path, const std::string& engine_id);
    bool UnloadEngine(const std::string& engine_id);
    bool SwitchEngine(const std::string& engine_id);
    std::vector<std::string> GetAvailableEngines();
    std::string GetCurrentEngine();
    
private:
    bool ExtractVSIX(const std::string& vsix_path, const std::filesystem::path& extract_dir);
    bool ValidateManifest(const nlohmann::json& manifest);
    bool LoadPluginFromDirectory(const std::filesystem::path& plugin_dir);
    void SavePluginState();
    void LoadPluginState();
    std::string GetSizeName(size_t size);
    
    // Engine management
    std::unordered_map<std::string, std::string> engines_; // id -> path
    std::string current_engine_id_;
};

// Singleton implementation
VSIXLoader& VSIXLoader::GetInstance() {
    static VSIXLoader instance;
    return instance;
}
```

### **vsix_loader.cpp** (Complete)
```cpp
#include "vsix_loader.h"
#include <fstream>
#include <sstream>
#include <algorithm>
#include <shlwapi.h>
#pragma comment(lib, "shlwapi.lib")
#include <zip.h>

VSIXLoader::VSIXLoader() {
    plugins_dir_ = std::filesystem::current_path() / "plugins";
    std::filesystem::create_directories(plugins_dir_);
    LoadPluginState();
}

VSIXLoader::~VSIXLoader() {
    SavePluginState();
}

bool VSIXLoader::Initialize(const std::string& plugins_dir) {
    std::lock_guard<std::mutex> lock(mutex_);
    plugins_dir_ = std::filesystem::path(plugins_dir);
    std::filesystem::create_directories(plugins_dir_);
    LoadPluginState();
    return true;
}

bool VSIXLoader::LoadPlugin(const std::string& vsix_path) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    if (!std::filesystem::exists(vsix_path)) {
        return false;
    }
    
    // Extract VSIX (zip file)
    std::filesystem::path extract_dir = plugins_dir_ / std::filesystem::path(vsix_path).stem();
    if (!ExtractVSIX(vsix_path, extract_dir)) {
        return false;
    }
    
    return LoadPluginFromDirectory(extract_dir);
}

bool VSIXLoader::ExtractVSIX(const std::string& vsix_path, const std::filesystem::path& extract_dir) {
    int err = 0;
    zip* z = zip_open(vsix_path.c_str(), 0, &err);
    if (!z) return false;
    
    std::filesystem::create_directories(extract_dir);
    
    zip_int64_t num_entries = zip_get_num_entries(z, 0);
    for (zip_int64_t i = 0; i < num_entries; i++) {
        const char* name = zip_get_name(z, i, 0);
        if (!name) continue;
        
        std::filesystem::path entry_path = extract_dir / name;
        std::filesystem::create_directories(entry_path.parent_path());
        
        zip_file* f = zip_fopen_index(z, i, 0);
        if (!f) continue;
        
        std::ofstream out(entry_path, std::ios::binary);
        char buffer[8192];
        zip_int64_t bytes_read;
        
        while ((bytes_read = zip_fread(f, buffer, sizeof(buffer))) > 0) {
            out.write(buffer, bytes_read);
        }
        
        zip_fclose(f);
        out.close();
    }
    
    zip_close(z);
    return true;
}

bool VSIXLoader::LoadPluginFromDirectory(const std::filesystem::path& plugin_dir) {
    // Load manifest
    std::filesystem::path manifest_path = plugin_dir / "manifest.json";
    if (!std::filesystem::exists(manifest_path)) {
        return false;
    }
    
    std::ifstream manifest_file(manifest_path);
    nlohmann::json manifest;
    try {
        manifest_file >> manifest;
    } catch (...) {
        return false;
    }
    
    if (!ValidateManifest(manifest)) {
        return false;
    }
    
    auto plugin = std::make_unique<VSIXPlugin>();
    plugin->id = manifest["id"];
    plugin->name = manifest["name"];
    plugin->version = manifest["version"];
    plugin->description = manifest["description"];
    plugin->author = manifest["author"];
    plugin->install_path = plugin_dir;
    plugin->enabled = true;
    plugin->manifest = manifest;
    
    // Load commands
    if (manifest.contains("commands")) {
        for (const auto& cmd : manifest["commands"]) {
            plugin->commands.push_back(cmd);
        }
    }
    
    // Load dependencies
    if (manifest.contains("dependencies")) {
        for (const auto& dep : manifest["dependencies"]) {
            plugin->dependencies.push_back(dep);
        }
    }
    
    // Load command handlers if present
    if (manifest.contains("command_handlers")) {
        for (const auto& [cmd, handler] : manifest["command_handlers"].items()) {
            RegisterCommand(cmd, [handler]() {
                // Execute handler (simplified)
                std::cout << "Executing: " << handler << std::endl;
            });
        }
    }
    
    // Load engine definitions if present
    if (manifest.contains("engines")) {
        for (const auto& [engine_id, engine_path] : manifest["engines"].items()) {
            LoadEngine(engine_path, engine_id);
        }
    }
    
    plugins_[plugin->id] = std::move(plugin);
    
    // Call onLoad if exists
    if (plugins_[plugin->id]->onLoad) {
        plugins_[plugin->id]->onLoad();
    }
    
    return true;
}

bool VSIXLoader::ValidateManifest(const nlohmann::json& manifest) {
    return manifest.contains("id") && manifest.contains("name") &&
           manifest.contains("version") && manifest.contains("description");
}

bool VSIXLoader::UnloadPlugin(const std::string& plugin_id) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    auto it = plugins_.find(plugin_id);
    if (it == plugins_.end()) {
        return false;
    }
    
    // Call onUnload if exists
    if (it->second->onUnload) {
        it->second->onUnload();
    }
    
    plugins_.erase(it);
    return true;
}

bool VSIXLoader::EnablePlugin(const std::string& plugin_id) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    auto it = plugins_.find(plugin_id);
    if (it == plugins_.end()) {
        return false;
    }
    
    it->second->enabled = true;
    return true;
}

bool VSIXLoader::DisablePlugin(const std::string& plugin_id) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    auto it = plugins_.find(plugin_id);
    if (it == plugins_.end()) {
        return false;
    }
    
    it->second->enabled = false;
    return true;
}

bool VSIXLoader::ReloadPlugin(const std::string& plugin_id) {
    if (!UnloadPlugin(plugin_id)) {
        return false;
    }
    
    // Find the original VSIX file
    std::filesystem::path vsix_path = plugins_dir_ / (plugin_id + ".vsix");
    if (!std::filesystem::exists(vsix_path)) {
        return false;
    }
    
    return LoadPlugin(vsix_path.string());
}

std::vector<VSIXPlugin*> VSIXLoader::GetLoadedPlugins() {
    std::lock_guard<std::mutex> lock(mutex_);
    
    std::vector<VSIXPlugin*> result;
    for (auto& pair : plugins_) {
        result.push_back(pair.second.get());
    }
    return result;
}

VSIXPlugin* VSIXLoader::GetPlugin(const std::string& plugin_id) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    auto it = plugins_.find(plugin_id);
    if (it != plugins_.end()) {
        return it->second.get();
    }
    return nullptr;
}

bool VSIXLoader::ExecutePluginCommand(const std::string& plugin_id, const std::string& command, const std::vector<std::string>& args) {
    VSIXPlugin* plugin = GetPlugin(plugin_id);
    if (!plugin || !plugin->enabled) {
        return false;
    }
    
    // Call onCommand if exists
    if (plugin->onCommand) {
        std::string full_command = command;
        for (const auto& arg : args) {
            full_command += " " + arg;
        }
        plugin->onCommand(full_command);
        return true;
    }
    
    return false;
}

void VSIXLoader::RegisterCommand(const std::string& command, std::function<void()> handler) {
    std::lock_guard<std::mutex> lock(mutex_);
    command_handlers_[command] = handler;
}

bool VSIXLoader::ExecuteCommand(const std::string& command) {
    std::lock_guard<std::mutex> lock(mutex_);
    
    auto it = command_handlers_.find(command);
    if (it != command_handlers_.end()) {
        it->second();
        return true;
    }
    
    return false;
}

std::string VSIXLoader::GetPluginHelp(const std::string& plugin_id) {
    VSIXPlugin* plugin = GetPlugin(plugin_id);
    if (!plugin) {
        return "Plugin not found";
    }
    
    std::string help = "Plugin: " + plugin->name + " v" + plugin->version + "\n";
    help += "Description: " + plugin->description + "\n";
    help += "Author: " + plugin->author + "\n";
    help += "Status: " + std::string(plugin->enabled ? "Enabled" : "Disabled") + "\n\n";
    
    if (!plugin->commands.empty()) {
        help += "Commands:\n";
        for (const auto& cmd : plugin->commands) {
            help += "  " + cmd + "\n";
        }
    }
    
    if (!plugin->dependencies.empty()) {
        help += "\nDependencies:\n";
        for (const auto& dep : plugin->dependencies) {
            help += "  " + dep + "\n";
        }
    }
    
    return help;
}

