    if (!hMapping) {
        CloseHandle(hFile);
        return results;
    }
    
    LPVOID pFile = MapViewOfFile(hMapping, FILE_MAP_READ, 0, 0, 0);
    if (!pFile) {
        CloseHandle(hMapping);
