bool CodexUltimate::LinkObject(const std::vector<std::string>& obj_files, const std::string& output_exe) {
    // Use LINK.EXE
    std::string command = "link /OUT:\"" + output_exe + "\"";
    for (const auto& obj : obj_files) {
        command += " \"" + obj + "\"";
    }
    int result = std::system(command.c_str());
    return result == 0;
}

std::string CodexUltimate::AnalyzeBinary(const std::string& binary_path) {
    std::string analysis = "Binary Analysis for: " + binary_path + "\n\n";
    
    // Disassemble first 100 instructions
    auto disassembly = Disassemble(binary_path, 0, 100);
    analysis += "First " + std::to_string(disassembly.size()) + " instructions:\n";
    for (const auto& inst : disassembly) {
        analysis += inst.address + ": " + inst.instruction + " " + inst.operands + "\n";
    }
    
    // Dump PE headers if applicable
    if (binary_path.ends_with(".exe") || binary_path.ends_with(".dll")) {
        auto pe_info = DumpPE(binary_path);
        analysis += "\nPE Header Analysis:\n";
        analysis += "Machine: " + pe_info.machine + "\n";
        analysis += "Sections: " + std::to_string(pe_info.sections.size()) + "\n";
    }
    
    return analysis;
}

